mapper.insert:


    	     SELECT case when max(doc_seq) is null then '00001'
				         else LPAD(CAST(max(doc_seq)::BIGINT +1 as TEXT),5,'0')
				          end as doc_seq
			   FROM esg.tb_employees_detail
			  WHERE write_year = #{writeYear}
			    AND doc_type = #{docType}
			    AND doc_no = #{docNo}


    	INSERT 
		  INTO esg.tb_employees_detail (write_year
		  							  , doc_type
		  							  , doc_no
		  							  , doc_seq
		  							  , comp_id
		  							  , gubun
		  							  , stakeholders
		  							  , requirements
		  							  , obligation
		  							  , risk
		  							  , chance
									  , created_at
									  , created_by
							   ) values (#{writeYear}
							   		  , #{docType}
							   		  , #{docNo}
							   		  , #{docSeq}
							   		  , #{compId}
							   		  , #{gubun}
							   		  , #{stakeholders}
							   		  , #{requirements}
							   		  , #{obligation}
							   		  , #{risk}
							   		  , #{chance}								  	  
								  	  , now()
								  	  , #{createdBy});

		INSERT INTO esg.tb_employees_detail_stakeholders (
			  write_year
			, doc_type
			, doc_no
			, doc_seq
			, comp_id
			, stakeholders
			, created_at
			, created_by
		)
		SELECT #{writeYear}
			 , #{docType}
			 , #{docNo}
			 , #{docSeq}
			 , #{compId}
			 , unnest(string_to_array(#{stakeholders}, ',')) stakeholders
			 , now()
			 , #{createdBy};

